={{ (function(){
  try {
    const rows = $('Tool - Obtener Siguiente ID Tutoria').all();
    const maxNum = Math.max(...rows.map(item => parseInt(String(item.json.id_tutoria || 'TUT1000000').replace('TUT','')) || 1000000));
    return 'TUT' + String(maxNum + 1).padStart(7,'0');
  } catch (e) {
    return 'TUT' + String(Date.now()).slice(-7);
  }
})() }}

