const output = $input.item.json.output;
const trigger = $('Telegram Trigger').first().json;
const chatId = trigger.message ? trigger.message.chat.id : trigger.callback_query.message.chat.id;

const body = {
  chat_id: chatId,
  text: output.mensaje,
  parse_mode: "Markdown"
};

if (output.opciones && output.opciones.length > 0) {
  body.reply_markup = {
    inline_keyboard: output.opciones.map(o => ([{ text: o.texto, callback_data: o.valor }]))
  };
}

return { json: { telegramBody: body } };

const raw = $input.item.json.output;
let text = typeof raw === 'string' ? raw : JSON.stringify(raw);

// Quitar posibles backticks de markdown (```json ... ``` o ``` ... ```)
text = text.trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

let parsed = null;

// Intento 1: parseo directo
try {
  parsed = JSON.parse(text);
} catch (e) {
  // Intento 2: extraer el primer objeto JSON balanceado dentro del texto
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    try {
      parsed = JSON.parse(text.slice(start, end + 1));
    } catch (e2) {
      parsed = null;
    }
  }
}

// Fallback: si no se pudo parsear o no tiene la forma esperada,
// usamos el texto completo como mensaje conversacional sin botones,
// para que el usuario SIEMPRE reciba una respuesta en Telegram.
if (!parsed || typeof parsed !== 'object' || typeof parsed.mensaje !== 'string') {
  parsed = { mensaje: text, opciones: [] };
}

if (!Array.isArray(parsed.opciones)) {
  parsed.opciones = [];
}

return { json: { output: parsed } };

const staticData = $getWorkflowStaticData('global');
if (!staticData.processedUpdateIds) {
  staticData.processedUpdateIds = [];
}

const updateId = $json.update_id;
let isDuplicate = false;

if (updateId !== undefined) {
  if (staticData.processedUpdateIds.includes(updateId)) {
    isDuplicate = true;
  } else {
    staticData.processedUpdateIds.push(updateId);
    // Mantener solo los últimos 50 para no crecer indefinidamente
    if (staticData.processedUpdateIds.length > 50) {
      staticData.processedUpdateIds.shift();
    }
  }
}

return { json: { ...$json, _isDuplicate: isDuplicate } };
